const params = $('Parse Job Params').item.json;
const usedResult = $('Get Used Topics').item.json.result;
const usedTopics = Array.isArray(usedResult) ? usedResult : [];

const genre = params.genre;
const genreTopics = topicData[genre] || topicData['Mystery'];

// Filter unused from selected genre
let available = genreTopics.filter(t => !usedTopics.includes(t));

// If genre exhausted, pick from all genres
if (available.length === 0) {
  const allTopics = Object.values(topicData).flat();
  available = allTopics.filter(t => !usedTopics.includes(t));
}

// If everything used (250+ videos!), reset and start again
if (available.length === 0) { available = genreTopics; }

const selectedTopic = available[Math.floor(Math.random() * available.length)];
const remaining = genreTopics.filter(t => !usedTopics.includes(t) && t !== selectedTopic).length;

return [{ json: { ...params, selectedTopic, topicsRemainingInGenre: remaining } }];

