const raw = $input.first().json.choices[0].message.content;
const params = $('Select Unique Topic').item.json;
let script;
try {
  const cleaned = raw.replace(/```json/g,'').replace(/```/g,'').trim();
  script = JSON.parse(cleaned);
} catch(e) {
  script = {
    title: params.selectedTopic,
    full_narration: 'What you are about to discover will change everything. The truth has been hidden for decades. Scientists were baffled. The evidence was overwhelming. And now you know why they kept it secret.',
    scenes: [
      { scene_number:1, visual_prompt: 'Dramatic dark cinematic opening, mysterious atmosphere, ' + params.visualPrompt, narration: 'What you are about to discover will change everything.', duration_sec:7 },
      { scene_number:2, visual_prompt: 'Revealing documentary shot, close-up details, ' + params.visualPrompt, narration: params.selectedTopic + '. The truth has been hidden for decades.', duration_sec:7 },
      { scene_number:3, visual_prompt: 'Tension building, dark shadows, ' + params.visualPrompt, narration: 'Scientists were baffled. No one could explain it.', duration_sec:7 },
      { scene_number:4, visual_prompt: 'Evidence reveal, dramatic lighting, ' + params.visualPrompt, narration: 'The evidence was overwhelming.', duration_sec:7 },
      { scene_number:5, visual_prompt: 'Climactic cinematic conclusion, ' + params.visualPrompt, narration: 'And now you know why they kept it secret.', duration_sec:7 }
    ]
  };
}
// Enforce exactly 5 scenes
if (!script.scenes) script.scenes = [];
while (script.scenes.length < 5) {
  script.scenes.push({ scene_number: script.scenes.length+1, visual_prompt: params.visualPrompt + ', cinematic scene', narration: 'The mystery deepens.', duration_sec:7 });
}
script.scenes = script.scenes.slice(0, 5);

return [{ json: {
  script, jobId: params.jobId, chatId: params.chatId,
  genre: params.genre, vstyle: params.vstyle, nstyle: params.nstyle,
  duration: params.duration, aspect_ratio: params.aspect_ratio,
  selectedTopic: params.selectedTopic,
  visualPrompt: params.visualPrompt, narrationInstr: params.narrationInstr,
  topicsRemainingInGenre: params.topicsRemainingInGenre
} }];
